import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { first } from 'rxjs/operators';
import { Account } from '@app/_models';
import { AccountService, AlertService } from '@app/_services';
import { AlertComponent } from '@app/_components/alert.component';

@Component({
  templateUrl: 'list.component.html',
  standalone: true,
  imports: [CommonModule, RouterLink, AlertComponent]
})
export class ListComponent implements OnInit {
  accounts!: Account[];

  constructor(private accountService: AccountService, private alertService: AlertService) { }

  ngOnInit() {
    this.accountService.getAll()
      .pipe(first())
      .subscribe(accounts => this.accounts = accounts);
  }

  deleteAccount(account: Account) {
    account.isDeleting = true;
    this.accountService.delete(account.id)
      .pipe(first())
      .subscribe(() => {
        this.accounts = this.accounts.filter(x => x.id !== account.id);
      });
  }
}
<h4>Accounts</h4>
<alert id="accounts-alert"></alert>
<a routerLink="add" class="btn btn-sm btn-success mb-3">Add Account</a>
<table class="table table-striped">
  <thead>
    <tr>
      <th>Name</th>
      <th>Email</th>
      <th>Role</th>
      <th>Verified</th>
      <th></th>
    </tr>
  </thead>
  <tbody>
    <tr *ngFor="let account of accounts">
      <td>{{account.title}} {{account.firstName}} {{account.lastName}}</td>
      <td>{{account.email}}</td>
      <td>{{account.role}}</td>
      <td>{{account.isVerified ? 'Yes' : 'No'}}</td>
      <td style="white-space: nowrap;">
        <a routerLink="edit/{{account.id}}" class="btn btn-sm btn-primary me-1">Edit</a>
        <button (click)="deleteAccount(account)" class="btn btn-sm btn-danger" [disabled]="account.isDeleting">
          <span *ngIf="account.isDeleting" class="spinner-border spinner-border-sm"></span>
          <span *ngIf="!account.isDeleting">Delete</span>
        </button>
      </td>
    </tr>
    <tr *ngIf="!accounts">
      <td colspan="5" class="text-center"><span class="spinner-border spinner-border-sm"></span></td>
    </tr>
  </tbody>
</table>
